import{_ as e,c as s,o as a,a5 as o}from"./chunks/framework.CgT1UzWm.js";const n="/system-diagram.png",m=JSON.parse('{"title":"The Power of Simplicity","titleTemplate":"NpgsqlRest","description":"How collapsing the standard data access pattern down to UI → RDBMS could save enough energy to power a small country.","frontmatter":{"layout":"doc","outline":[2,3],"title":"The Power of Simplicity","titleTemplate":"NpgsqlRest","description":"How collapsing the standard data access pattern down to UI → RDBMS could save enough energy to power a small country.","badge":"human","head":[["meta",{"name":"keywords","content":"postgresql, npgsqlrest, software architecture, simplicity, data access pattern, orm, rest api, energy efficiency, database first"}],["meta",{"property":"og:title","content":"The Power of Simplicity"}],["meta",{"property":"og:description","content":"How collapsing the standard data access pattern down to UI → RDBMS could save enough energy to power a small country."}],["meta",{"property":"og:type","content":"article"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"The Power of Simplicity"}]]},"headers":[],"relativePath":"blog/the-power-of-simplicity.md","filePath":"blog/the-power-of-simplicity.md"}'),i={name:"blog/the-power-of-simplicity.md"};function r(l,t,p,c,h,d){return a(),s("div",null,t[0]||(t[0]=[o('<h1 id="the-power-of-simplicity" tabindex="-1">The Power of Simplicity <a class="header-anchor" href="#the-power-of-simplicity" aria-label="Permalink to &quot;The Power of Simplicity&quot;">​</a></h1><p class="blog-meta"><span>March 2026</span> · <span class="tag">Architecture</span><span class="tag">Opinion</span></p><hr><p>The standard data access pattern for modern, business, data-driven applications is this:</p><blockquote><p><strong>UI</strong> (browser client) → <strong>Fetch</strong> (Browser API calls) → <strong>Server Endpoint</strong> (Controller) → <strong>Service Layer</strong> → <strong>Repository</strong> → <strong>ORM</strong> → <strong>SQL</strong> (Automatic with ORM) → <strong>RDBMS</strong></p></blockquote><p>We do this so that we can mock the Repository and test logic in the Service. The problem with this approach is that once you realize how trivial it is to wire up database-aware tests - you can call them what you like, integration tests, database tests, whatever - once you realize that, you also realize you can collapse at least two layers:</p><blockquote><p><strong>UI</strong> (browser client) → <strong>Fetch</strong> (Browser API calls) → <strong>Server Endpoint</strong> (Controller) → <strong>ORM</strong> → <strong>SQL</strong> (Automatic with ORM) → <strong>RDBMS</strong></p></blockquote><p>This is much, much simpler. But then, as you become proficient with SQL and you realize you can do things that ORM can&#39;t generate, and in many cases faster and more efficient, you realize this can be even simpler:</p><blockquote><p><strong>UI</strong> (browser client) → <strong>Fetch</strong> (Browser API calls) → <strong>Server Endpoint</strong> (Controller) → <strong>SQL</strong> → <strong>RDBMS</strong></p></blockquote><p>And then you realize SQL actually has a rich type system - at least something mature and advanced as PostgreSQL does - and that type system can be used as a contract, and that Controller code is just boring glue code that can and should be automated:</p><blockquote><p><strong>UI</strong> (browser client) → <strong>Fetch</strong> (Browser API calls) → <strong>Automatic Server Endpoint</strong> (Controller) → <strong>SQL</strong> → <strong>RDBMS</strong></p></blockquote><p>But why stop there? If the controller can be automated, why not generate those Fetch calls as well? And that SQL can be stored in the RDBMS. Finally, this is what we have, basically:</p><blockquote><p><strong>UI</strong> → <strong>RDBMS</strong></p></blockquote><p><img src="'+n+`" alt="System Diagram"></p><p>Now, if we all start doing software architecture like that, imagine how many tokens and energy we could save... That is what I call the energy efficiency. In a time of looming energy crisis, we could probably power a small country with the power of simplicity.</p><hr><p>Starting with NpgsqlRest 3.12.0, this simplification reached its logical conclusion with <a href="/config/sql-file-source.html">SQL File Endpoints</a>. You don&#39;t even need to store your SQL in the database as functions anymore. Write a <code>.sql</code> file, add a comment annotation, and it becomes a REST endpoint:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- sql/get-users.sql</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- HTTP GET</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- @param $1 department</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, email </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> department </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><p>That&#39;s it. No <code>CREATE FUNCTION</code>, no database deployment step. Just a file on disk that becomes <code>GET /api/get-users?department=engineering</code>. TypeScript types are auto-generated. The SQL stays version-controlled in your repo.</p><p>For complex business logic that needs to evolve independently from the application — like the <a href="/blog/what-have-stored-procedures-ever-done-for-us.html">data contracts</a> story — PostgreSQL functions remain the right choice. But for straightforward queries, SQL files remove the last bit of ceremony between your intent and a working API endpoint.</p><p>Three endpoint sources, one binary, zero boilerplate:</p><ul><li><strong>SQL Files</strong> — write a query, get an endpoint</li><li><strong>Functions</strong> — formal data contracts with static type checking</li><li><strong>Tables</strong> — automatic CRUD generation</li></ul><p>If you want to learn how to do this with PostgreSQL, check out the <a href="/guide/quick-start.html">Quick Start Guide</a> or dive into the <a href="/blog/">Tutorials</a>.</p>`,23)]))}const u=e(i,[["render",r]]);export{m as __pageData,u as default};
